import heapq

def huffman_codes(freq):
    heap = [(f, i, char) for i, (char, f) in enumerate(freq.items())]
    heapq.heapify(heap)
    nodes = {char: '' for char in freq}
    while len(heap) > 1:
        f1, _, left = heapq.heappop(heap)
        f2, _, right = heapq.heappop(heap)
        for char in (left if isinstance(left, str) else left):
            nodes[char] = '0' + nodes[char] if isinstance(left, str) else nodes.get(char, '')
        merged = (f1 + f2, len(heap), (left, right))
        heapq.heappush(heap, merged)
    return nodes
